const COMPASS = ["", "N", "NE", "E", "SE", "S", "SW", "W", "NW"] as const;
const CARDINAL = new Set(["N", "E", "S", "W"]);

/**
 * Convert an OCAD Column-D code ("X.YYY") to the IOF SVG filename key.
 * Example: "2.004" → "2.4", "1.010" → "1.10"
 */
function ocadDtoIof(code: string): string | null {
  const [grp, sub] = code.split(".");
  if (!sub) return null;
  const key = `${parseInt(grp, 10)}.${parseInt(sub, 10)}`;
  return key in IOF_SYMBOLS ? key : null;
}

/**
 * Convert an OCAD Column-C code ("0.XXX") to the IOF SVG filename key.
 * Handles compass directions (cardinal → 0.1+dir, inter-cardinal → 0.2+dir)
 * and non-directional (upper=0.3, lower=0.4, middle=0.5).
 */
function ocadCtoIof(code: string): string | null {
  const sub = parseInt(code.split(".")[1] ?? "0", 10);
  if (sub === 3 || sub === 300) return "0.3";
  if (sub === 4 || sub === 400) return "0.4";
  if (sub === 5 || sub === 500) return "0.5";
  const compassIdx = sub >= 100 ? sub % 10 : sub;
  const dir = COMPASS[compassIdx];
  if (!dir) return null;
  const prefix = CARDINAL.has(dir) ? "0.1" : "0.2";
  const key = `${prefix}${dir}`;
  return key in IOF_SYMBOLS ? key : null;
}

const OCAD_G_NONDIRECTIONAL: Record<number, string> = {
  8: "11.9",   // Upper part
  9: "11.10",  // Lower part
  10: "11.11", // Top
  11: "11.13", // Foot (non-directional)
  13: "11.12", // Beneath
  14: "11.15", // Between
};

const OCAD_G_RANGE10_TO_IOF: Record<number, string> = {
  12: "11.14", // Foot (directional)
  14: "11.14",
  15: "11.5",  // Corner outside
  16: "11.6",  // Tip
  17: "11.8",  // End
};

const OCAD_G_TYPE_TO_IOF: Record<number, string> = {
  1: "11.1", // Side
  2: "11.2", // Edge
  3: "11.3", // Part
  4: "11.4", // Corner inside
  5: "11.5", // Corner outside
  6: "11.6", // Tip
  7: "11.8", // End
};

/**
 * Convert an OCAD Column-G code ("11.XXX") to the IOF SVG filename key.
 */
function ocadGtoIof(code: string): string | null {
  const sub = parseInt(code.split(".")[1] ?? "0", 10);
  if (sub < 100) {
    const mapped = OCAD_G_NONDIRECTIONAL[sub];
    return mapped && mapped in IOF_SYMBOLS ? mapped : null;
  }
  const compassIdx = sub % 10;
  const dir = COMPASS[compassIdx];
  if (!dir) return null;

  const range10 = Math.floor(sub / 10);
  const r10base = OCAD_G_RANGE10_TO_IOF[range10];
  if (r10base) {
    const key = `${r10base}${dir}`;
    return key in IOF_SYMBOLS ? key : null;
  }

  const type = Math.floor(sub / 100);
  const tbase = OCAD_G_TYPE_TO_IOF[type];
  if (tbase) {
    const key = `${tbase}${dir}`;
    return key in IOF_SYMBOLS ? key : null;
  }
  return null;
}

const OCAD_F_MAP: Record<string, string> = {
  "10.001": "10.1",
  "10.002": "10.2",
  "11.001": "11.7",
};

/**
 * Convert an OCAD Column-F code to the IOF SVG filename key.
 */
function ocadFtoIof(code: string): string | null {
  const mapped = OCAD_F_MAP[code];
  if (mapped && mapped in IOF_SYMBOLS) return mapped;
  const [grp, sub] = code.split(".");
  if (!sub) return null;
  const key = `${parseInt(grp, 10)}.${parseInt(sub, 10)}`;
  return key in IOF_SYMBOLS ? key : null;
}

/**
 * Get the IOF symbol SVG inner content for a given OCAD description,
 * organized by IOF column (C, D, E, F, G).
 * Returns an object with symbol SVG strings (already colored) for each column,
 * or null for columns with no matching symbol.
 */
export function getDescriptionSymbols(
  desc: { c?: string; d?: string; g?: string; s?: string; f?: string },
  color = "#c026d3",
): {
  colC: string | null;
  colD: string | null;
  colE: string | null; // dimensions text, not a symbol
  colF: string | null;
  colG: string | null;
} {
  const colorize = (svg: string) =>
    svg.replace(/stroke="black"/g, `stroke="${color}"`)
       .replace(/fill="black"/g, `fill="${color}"`);

  const dKey = desc.d ? ocadDtoIof(desc.d) : null;
  const cKey = desc.c ? ocadCtoIof(desc.c) : null;
  const gKey = desc.g ? ocadGtoIof(desc.g) : null;
  const fKey = desc.f ? ocadFtoIof(desc.f) : null;

  return {
    colC: cKey ? colorize(IOF_SYMBOLS[cKey]) : null,
    colD: dKey ? colorize(IOF_SYMBOLS[dKey]) : null,
    colE: desc.s ? desc.s.replace(",", ".") + "m" : null,
    colF: fKey ? colorize(IOF_SYMBOLS[fKey]) : null,
    colG: gKey ? colorize(IOF_SYMBOLS[gKey]) : null,
  };
}
